With[{
  (* Pillar Seed *)
  b3 = 24,

  (* Established experimental inputs *)
  H0late = 73.04,    (* SH0ES 2025, km/s/Mpc *)
  H0planck = 67.4,   (* Planck 2018, km/s/Mpc *)
  planckErr = 0.5,   (* Planck 1-sigma *)

  (* Cosmological parameters *)
  OmegaM = 0.311,
  OmegaDE = 0.689,
  zCMB = 1100         (* CMB last scattering *)
},
  (* Log-scaling relaxation factor from G2 Ricci flow *)
  relaxation = 1 + Log[1 + zCMB] / b3;

  (* Raw v14.2 formula: H(z) = H0_late * (1+z)^1.5 / relaxation(z) *)
  Hraw = H0late * (1 + zCMB)^1.5 / relaxation;
  H0rawInferred = Hraw / Sqrt[OmegaM * (1 + zCMB)^3 + OmegaDE];
  rawDeviation = Abs[H0rawInferred - H0planck] / planckErr;

  (* E(z) for LCDM *)
  Ez = Sqrt[OmegaM * (1 + zCMB)^3 + OmegaDE];

  (* Ricci flow interpolation (v16.1) *)
  kGimel = b3/2 + 1/Pi;   (* ~12.318 *)
  tauRicci = kGimel / b3; (* ~0.513 *)
  zStar = 1 / tauRicci;   (* ~1.95 *)
  fInterp = 1 / (1 + (zCMB/zStar)^2);
  H0eff = H0late * fInterp + H0planck * (1 - fInterp);
  HcmbInterp = H0eff * Ez;

  (* Inferred H0_early from interpolated method *)
  H0earlyInferred = HcmbInterp / Ez;

  (* Deviation from Planck *)
  deviation = Abs[H0earlyInferred - H0planck] / planckErr;

  (* Circularity diagnostic: weight on H0_early endpoint at z=1100 *)
  weightOnH0early = 1 - fInterp;

  {N[relaxation, 6], N[H0earlyInferred, 8], N[deviation, 6], deviation < 2.0,
   N[H0rawInferred, 6], N[rawDeviation, 4], N[weightOnH0early, 10]}
]
